use Data::Dumper;

my $plugin_dir = $ENV{PLUGIN_DIR} || './plugins';
my $config_file = $ENV{CONFIG_FILE} || './config.yaml';

my %plugins;
my %plugin_contexts;

sub load_config {
    my $config_path = shift;
    return {} unless -e $config_path;
    
    if ($config_path =~ /\.json$/i) {
        my $json_text = read_file($config_path);
        return decode_json($json_text);
    } elsif ($config_path =~ /\.ya?ml$/i) {
        return YAML::XS::LoadFile($config_path);
    }
    return {};
}

sub load_plugins {
    my $dir = shift;
    return unless -d $dir;
    
    opendir(my $dh, $dir) or die "Cannot open plugin directory: $!";
    while (my $file = readdir($dh)) {
        next if $file =~ /^\./;
        my $full_path = File::Spec->catfile($dir, $file);
        
        if ($file =~ /\.(pl|pm)$/i) {
            load_plugin_file($full_path, $file);
        } elsif ($file =~ /\.yaml$/i || $file =~ /\.json$/i) {
            load_plugin_config($full_path, $file);
        }
    }
    closedir($dh);
}

sub load_plugin_file {
    my ($path, $name) = @_;
    my $code = read_file($path);
    $name =~ s/\.(pl|pm)$//i;
    $plugins{$name} = $code;
    print "Loaded plugin file: $name\n";
}

sub load_plugin_config {
    my ($path, $name) = @_;
    my $config = load_config($path);
    
    foreach my $plugin_name (keys %$config) {
        my $plugin_def = $config->{$plugin_name};
        if (ref($plugin_def) eq 'HASH' && $plugin_def->{code}) {
            $plugins{$plugin_name} = $plugin_def->{code};
            $plugin_contexts{$plugin_name} = $plugin_def->{context} || {};
            print "Loaded plugin from config: $plugin_name\n";
        }
    }
}

sub execute_plugin {
    my ($plugin_name, $args) = @_;
    $args ||= {};
    
    unless (exists $plugins{$plugin_name}) {
        die "Plugin '$plugin_name' not found\n";
    }
    
    my $plugin_code = $plugins{$plugin_name};
    my $context = $plugin_contexts{$plugin_name} || {};
    
    my $result;
    my $error;
    
    local $@;
    eval {
        my %plugin_env = (
            args => $args,
            context => $context,
            plugin_name => $plugin_name,
        );
        
        no strict 'refs';
        no warnings 'redefine';
        
        local *plugin_args = sub { return $args };
        local *plugin_context = sub { return $context };
        local *plugin_log = sub { print "[Plugin: $plugin_name] ", @_, "\n" };
        
        $result = eval($plugin_code);
        
        if ($@) {
            die $@;
        }
    };
    
    if ($@) {
        $error = $@;
        print STDERR "Error executing plugin '$plugin_name': $error\n";
        return { success => 0, error => $error };
    }
    
    return { success => 1, result => $result };
}

sub register_plugin {
    my ($name, $code, $context) = @_;
    $plugins{$name} = $code;
    $plugin_contexts{$name} = $context || {};
    print "Registered plugin: $name\n";
}

sub list_plugins {
    return keys %plugins;
}

sub get_plugin_info {
    my $name = shift;
    return unless exists $plugins{$name};
    
    return {
        name => $name,
        code_length => length($plugins{$name}),
        has_context => exists $plugin_contexts{$name},
        context => $plugin_contexts{$name},
    };
}

